from jose import jwt, JWTError from datetime import datetime, timedelta
ALGORITHM = "RS256" # asymmetric; HS256 only when issuer == single verifier ALLOWED_ALGORITHMS = ["RS256", "EdDSA"]
def verify_token(token: str, audience: str, issuer: str) -> dict: try: payload = jwt.decode( token, PUBLIC_KEY, algorithms=ALLOWED_ALGORITHMS, audience=audience, issuer=issuer, ) return payload except JWTError as e: raise HTTPException(401, f"Invalid token: {e}")
